const body = $json.body ?? $json;

const pick = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '') ?? '';

const nome = pick(body.nome, body.name, body.nomeCliente, body.customerName);
const telefone = pick(body.telefone, body.phone, body.whatsapp, body.numero);
const procedimento = pick(body.procedimento, body.procedure, body.servico, body.service);
const objetivo = pick(body.objetivo, body.goal, body.intencao, body.intention);
const urgencia = pick(body.urgencia, body.urgency, body.prazo, body.timeframe);
const origem = pick(body.origem, body.source, body.channel, 'landing-page');

const missingFields = [];
if (!nome) missingFields.push('nome');
if (!telefone) missingFields.push('telefone');
if (!procedimento) missingFields.push('procedimento');
if (!objetivo) missingFields.push('objetivo');
if (!urgencia) missingFields.push('urgencia');

const isQualified = missingFields.length === 0;
const leadStage = isQualified ? 'qualificado' : 'em_triagem';
const priority = urgencia.toLowerCase().includes('hoje') || urgencia.toLowerCase().includes('semana') ? 'alta' : 'normal';

const assistantReply = isQualified
  ? `Perfeito, ${nome}. Já identifiquei seu interesse em ${procedimento}. Vou encaminhar sua avaliação para a equipe da Harmonny e você receberá o retorno com prioridade ${priority}.`
  : `Para seguir com seu atendimento na Harmonny, preciso de: ${missingFields.join(', ')}.`;

const secretarySummary = [
  `Nome: ${nome || 'não informado'}`,
  `Telefone: ${telefone || 'não informado'}`,
  `Procedimento: ${procedimento || 'não informado'}`,
  `Objetivo: ${objetivo || 'não informado'}`,
  `Urgência: ${urgencia || 'não informado'}`,
  `Origem: ${origem}`,
  `Status: ${leadStage}`,
  `Prioridade: ${priority}`,
].join('\n');

return [{
  json: {
    nome,
    telefone,
    procedimento,
    objetivo,
    urgencia,
    origem,
    missingFields,
    isQualified,
    leadStage,
    priority,
    assistantReply,
    secretarySummary,
  },
}];
